/* Standard GCC-emitted CRT routine: deregisters TM clone table if the
 * weak symbol _ITM_deregisterTMCloneTable resolved to a non-NULL address. */

extern void __attribute__((weak)) _ITM_deregisterTMCloneTable(void *);
extern char __TMC_END__[];

void deregister_tm_clones(void)
{
    if (_ITM_deregisterTMCloneTable == 0)
        return;

    _ITM_deregisterTMCloneTable(__TMC_END__);
}

